mapper.select:
SELECT A.BUYER_CD , A.BID_NUM , A.BID_CNT , A.ANN_NO , A.BUYER_NM ,(CASE WHEN A.ORI_BID_STATUS IN ('2303', '2330') THEN '[취소]' || A.ANN_ITEM ELSE A.ANN_ITEM END ) AS ANN_ITEM , A.ANN_DATE , A.CONT_TYPE1 , A.CONT_TYPE1_LOC , A.CONT_TYPE2 , A.CONT_TYPE2_LOC , A.CONT_TYPE3 , A.CONT_TYPE3_LOC , A.APP_BEGIN_DATETIME , A.APP_END_DATETIME , A.BID_STATUS ,(CASE WHEN A.ORI_BID_STATUS IN ('2302', '2303', '2320', '2330') THEN GETCOMCODE(A.GATE_CD, 'M340', A.ORI_BID_STATUS, 0, #{ses.langCd}) ELSE A.BID_STATUS_LOC END) AS BID_STATUS_LOC , A.ORI_BID_STATUS , A.BID_USER_ID , A.BID_USER_NM , A.EV_USER_ID , A.EV_USER_NM , A.SIGN_STATUS , A.MOD_POSSIBLE_FLAG , A.TECH_EV_TYPE FROM ( SELECT HD.GATE_CD , HD.BUYER_CD ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'BID', HD.BID_NUM, HD.BID_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.ANN_NO , HD.ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1, GETCOMCODE(HD.GATE_CD, 'M301', HD.CONT_TYPE1, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , HD.CONT_TYPE2, GETCOMCODE(HD.GATE_CD, 'M302', HD.CONT_TYPE2, 0, #{ses.langCd}) AS CONT_TYPE2_LOC , HD.CONT_TYPE3, GETCOMCODE(HD.GATE_CD, 'M303', HD.CONT_TYPE3, 0, #{ses.langCd}) AS CONT_TYPE3_LOC , SUBSTR(HD.APP_BEGIN_DATE, 1, 4) '-' SUBSTR(HD.APP_BEGIN_DATE, 5, 2) '-' SUBSTR(HD.APP_BEGIN_DATE, 7, 2) ' ' SUBSTR(HD.APP_BEGIN_TIME, 1, 2) ':' SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_DATETIME , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,getBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') AS BID_STATUS ,getBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'LOC') AS BID_STATUS_LOC , HD.BID_STATUS AS ORI_BID_STATUS , HD.BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.EV_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.EV_USER_ID, #{ses.langCd}) AS EV_USER_NM , HD.BID_NUM , HD.BID_CNT , HD.SIGN_STATUS ,(CASE WHEN (SELECT COUNT(AP.VENDOR_CD) FROM STOCBDAP AP WHERE AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.DEL_FLAG = '0' AND AP.APP_DATE IS NOT NULL) > 0 THEN 'N' ELSE 'Y' END) AS MOD_POSSIBLE_FLAG , HD.TECH_EV_TYPE , HD.APP_BEGIN_DATE ,(CASE WHEN HD.SIGN_STATUS != 'E' THEN '1' WHEN HD.BID_STATUS = '2303' THEN '1' WHEN SYSDATE > (HD.APP_BEGIN_DATE HD.APP_BEGIN_TIME, 'YYYYMMDDHH24MISS') THEN (CASE WHEN HD.CONT_TYPE2 IN ('TD', 'TS', 'NE') AND HD.TECH_EV_TYPE = '20' THEN (CASE WHEN (SELECT COUNT(EU.PROGRESS_CD) FROM STOCBDEU EU WHERE EU.GATE_CD = HD.GATE_CD AND EU.BUYER_CD = HD.BUYER_CD AND EU.EI_NUM = HD.EI_NUM AND EU.DEL_FLAG = '0' AND EU.PROGRESS_CD = '100') > 0 THEN '1' ELSE '0' END) ELSE '0' END) ELSE '1' END) EU_PROGRESS_FLAG FROM STOCBDHD HD WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.DEL_FLAG = '0' AND HD.BID_STATUS NOT IN ('1300', '9999')
AND HD.ANN_DATE >= #{ANN_DATE_FROM} AND HD.ANN_DATE <= #{ANN_DATE_TO}
AND getBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') = #{BID_STATUS}
AND HD.BID_USER_ID = #{BID_USER_ID}
AND UPPER(GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{BID_USER_NM}) '%'
AND UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(REPLACE(HD.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_ITEM}, ' ', '')) '%'
AND EXISTS (SELECT 1 FROM STOCBDDT DT WHERE DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.BID_NUM = HD.BID_NUM AND DT.BID_CNT = HD.BID_CNT
AND UPPER(DT.PR_BUYER_CD) LIKE '%' UPPER(#{BUYER_CD}) '%'
AND UPPER(getCustName(DT.GATE_CD, DT.PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND DT.DEL_FLAG = '0')
) A WHERE A.EU_PROGRESS_FLAG = '1' ORDER BY A.BID_NUM, A.BID_CNT

SELECT (CASE WHEN SIGN_STATUS = 'P' THEN 'N' ELSE 'Y' END) 
  FROM STOCBDHD 
 WHERE GATE_CD  = #{ses.gateCd} 
   AND BUYER_CD = #{BUYER_CD} 
   AND BID_NUM  = #{BID_NUM} 
   AND BID_CNT  = #{BID_CNT}

