UPDATE STOCBDHD SET
	   MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , EV_USER_ID = #{EV_USER_ID}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM  = #{BID_NUM}
   AND BID_CNT  = #{BID_CNT}

