SELECT A.ANN_NO, A.ANN_DATE, A.ANN_ITEM ,A.CONT_TYPE1, A.CONT_TYPE2, A.CONT_TYPE3 ,A.TCO_FLAG, A.TCO_YEAR_CNT ,A.CUR, A.PR_AMT, A.VAT_TYPE ,A.ESTM_OPEN_FLAG, A.ESTM_LIMIT_RATE ,A.FINA_SOLV_FLAG, A.DIFF_GUAR_FLAG ,A.RATE_CURR, A.RATE_SDEPT, A.MIN_TECH_SCORE, A.MIN_TOT_SCORE ,A.PRC_SCORE, A.TECH_SCORE, A.BASIC_AMT, A.CONF_STD_SCORE, A.SB_LIMIT_RATE ,A.CONT_TERM, A.VOTE_LIMIT_CNT ,A.APP_BEGIN_DATE, A.APP_BEGIN_TIME, A.APP_BEGIN_MIN ,A.APP_END_DATE, A.APP_END_TIME, A.APP_END_MIN ,A.APP_PLACE, A.ESTM_TYPE, A.LIMIT_CRIT, A.PROM_CRIT ,A.BID_USER_ID, A.BID_USER_NM ,A.ESTM_USER_ID, A.ESTM_USER_NM ,A.OPEN_USER_ID, A.OPEN_USER_NM ,A.EV_TPL_CNT, A.EV_TPL_NUM, A.EI_NUM ,A.EV_USER_ID, A.EV_USER_NM ,A.TECH_EV_TYPE, A.APP_ETC, A.ATT_FILE_NUM ,A.ANNO_OPEN_FLAG, A.ANNO_FLAG ,A.ANNO_DATE, A.ANNO_TIME_FROM, A.ANNO_MIN_FROM, A.ANNO_TIME_TO, A.ANNO_MIN_TO ,A.ANNO_PLACE, A.ANNO_NOTIFIER, A.ANNO_RESP, A.ANNO_RMK ,A.PROP_OPEN_FLAG, A.PROP_FLAG ,A.PROP_DATE, A.PROP_TIME_FROM, A.PROP_MIN_FROM, A.PROP_TIME_TO, A.PROP_MIN_TO ,A.PROP_PLACE, A.PROP_NOTIFIER, A.PROP_RESP, A.PROP_RMK ,A.BUYER_CD, A.DEPT_CD ,A.BID_NUM, A.BID_CNT, A.ORI_BID_CNT ,A.APP_DOC_NUM, A.APP_DOC_CNT, A.BID_STATUS, A.SIGN_STATUS ,A.VENDOR_LIST, A.VENDOR_NMS, A.VENDOR_CDS ,PG.BID_BEGIN_DATE ,SUBSTR(PG.BID_BEGIN_TIME, 1, 2) AS BID_BEGIN_TIME ,SUBSTR(PG.BID_BEGIN_TIME, 3, 2) AS BID_BEGIN_MIN ,PG.BID_END_DATE ,SUBSTR(PG.BID_END_TIME, 1, 2) AS BID_END_TIME ,SUBSTR(PG.BID_END_TIME, 3, 2) AS BID_END_MIN ,PG.OPEN_DATE ,SUBSTR(PG.OPEN_TIME, 1, 2) AS OPEN_TIME ,SUBSTR(PG.OPEN_TIME, 3, 2) AS OPEN_MIN FROM ( SELECT HD.GATE_CD, HD.ANN_NO, HD.ANN_DATE, HD.ANN_ITEM ,HD.CONT_TYPE1, HD.CONT_TYPE2, HD.CONT_TYPE3 ,HD.TCO_FLAG, HD.TCO_YEAR_CNT ,HD.CUR, HD.PR_AMT, HD.VAT_TYPE ,HD.ESTM_OPEN_FLAG, HD.ESTM_LIMIT_RATE ,HD.FINA_SOLV_FLAG, HD.DIFF_GUAR_FLAG ,HD.RATE_CURR, HD.RATE_SDEPT, HD.MIN_TECH_SCORE, HD.MIN_TOT_SCORE ,HD.PRC_SCORE, HD.TECH_SCORE, HD.BASIC_AMT, HD.CONF_STD_SCORE, HD.SB_LIMIT_RATE ,HD.CONT_TERM, HD.VOTE_LIMIT_CNT ,HD.APP_BEGIN_DATE ,SUBSTR(HD.APP_BEGIN_TIME, 1, 2) AS APP_BEGIN_TIME ,SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_MIN ,HD.APP_END_DATE ,SUBSTR(HD.APP_END_TIME, 1, 2) AS APP_END_TIME ,SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_MIN ,HD.APP_PLACE, HD.ESTM_TYPE, HD.LIMIT_CRIT, HD.PROM_CRIT ,HD.BID_USER_ID, GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM ,HD.ESTM_USER_ID, GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM ,HD.OPEN_USER_ID, GETUSERNAME(HD.GATE_CD, HD.OPEN_USER_ID, #{ses.langCd}) AS OPEN_USER_NM ,(CASE WHEN HD.EI_NUM IS NOT NULL THEN 1 ELSE 0 END) AS EV_TPL_CNT ,HD.EV_TPL_NUM, HD.EI_NUM ,HD.EV_USER_ID, GETUSERNAME(HD.GATE_CD, HD.EV_USER_ID, #{ses.langCd}) AS EV_USER_NM ,HD.TECH_EV_TYPE, HD.APP_ETC, HD.ATT_FILE_NUM ,HD.ANNO_OPEN_FLAG, HD.ANNO_FLAG ,HD.ANNO_DATE ,SUBSTR(HD.ANNO_TIME_FROM, 1, 2) AS ANNO_TIME_FROM ,SUBSTR(HD.ANNO_TIME_FROM, 3, 2) AS ANNO_MIN_FROM ,SUBSTR(HD.ANNO_TIME_TO, 1, 2) AS ANNO_TIME_TO ,SUBSTR(HD.ANNO_TIME_TO, 3, 2) AS ANNO_MIN_TO ,HD.ANNO_PLACE ,HD.ANNO_NOTIFIER AS ANNO_NOTIFIER ,HD.ANNO_RESP AS ANNO_RESP ,HD.ANNO_RMK, HD.PROP_OPEN_FLAG, HD.PROP_FLAG ,HD.PROP_DATE ,SUBSTR(HD.PROP_TIME_FROM, 1, 2) AS PROP_TIME_FROM ,SUBSTR(HD.PROP_TIME_FROM, 3, 2) AS PROP_MIN_FROM ,SUBSTR(HD.PROP_TIME_TO, 1, 2) AS PROP_TIME_TO ,SUBSTR(HD.PROP_TIME_TO, 3, 2) AS PROP_MIN_TO ,HD.PROP_PLACE ,HD.PROP_NOTIFIER AS PROP_NOTIFIER ,HD.PROP_RESP AS PROP_RESP ,HD.PROP_RMK ,HD.BUYER_CD, HD.DEPT_CD ,HD.BID_NUM, (CASE WHEN (#{baseDataType} = 'ModBID' OR #{baseDataType} = 'CancelBID') THEN TO_NUMBER(HD.BID_CNT) + 1 ELSE HD.BID_CNT END) AS BID_CNT ,HD.BID_CNT AS ORI_BID_CNT ,HD.BID_STATUS ,(CASE WHEN (#{baseDataType} = 'ModBID' OR #{baseDataType} = 'CancelBID' OR #{baseDataType} = 'ReBID' OR HD.SIGN_STATUS = 'T') THEN '' ELSE HD.APP_DOC_NUM END) AS APP_DOC_NUM ,(CASE WHEN (#{baseDataType} = 'ModBID' OR #{baseDataType} = 'CancelBID' OR #{baseDataType} = 'ReBID' OR HD.SIGN_STATUS = 'T') THEN '' ELSE TO_CHAR(HD.APP_DOC_CNT) END) AS APP_DOC_CNT ,(CASE WHEN (#{baseDataType} = 'ModBID' OR #{baseDataType} = 'CancelBID' OR #{baseDataType} = 'ReBID') THEN '' ELSE HD.SIGN_STATUS END) AS SIGN_STATUS ,(SELECT COUNT(AP.VENDOR_CD) FROM STOCBDAP AP WHERE AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.DEL_FLAG = '0') AS VENDOR_LIST ,(SELECT SUBSTR(XMLAGG(XMLELEMENT(A, ', ' GETVENDORNAME(AP.GATE_CD, AP.VENDOR_CD, #{ses.langCd})) ORDER BY AP.VENDOR_CD).EXTRACT('//text()'), 2) FROM STOCBDAP AP WHERE AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.DEL_FLAG = '0') AS VENDOR_NMS ,(SELECT SUBSTR(XMLAGG(XMLELEMENT(A, ',' AP.VENDOR_CD) ORDER BY AP.VENDOR_CD).EXTRACT('//text()'), 2) FROM STOCBDAP AP WHERE AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.DEL_FLAG = '0') AS VENDOR_CDS FROM STOCBDHD HD WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD}
AND HD.BID_NUM = #{BID_NUM} AND HD.BID_CNT = #{BID_CNT}
AND HD.APP_DOC_NUM = #{APP_DOC_NUM} AND HD.APP_DOC_CNT = #{APP_DOC_CNT}
) A LEFT JOIN STOCBDPG PG ON (PG.GATE_CD = A.GATE_CD AND PG.BUYER_CD = A.BUYER_CD AND PG.BID_NUM = A.BID_NUM AND PG.BID_CNT = A.ORI_BID_CNT AND PG.DEL_FLAG = '0') WHERE PG.VOTE_CNT = (SELECT MAX(P.VOTE_CNT) FROM STOCBDPG P WHERE P.GATE_CD = A.GATE_CD AND P.BUYER_CD = A.BUYER_CD AND P.BID_NUM = A.BID_NUM AND P.BID_CNT = A.ORI_BID_CNT AND P.DEL_FLAG = '0')

