			,#{BUYER_CD} AS BUYER_CD
			,#{BID_NUM} AS BID_NUM
			,#{BID_CNT} AS BID_CNT
		 ) B
	  ON (BDHD.GATE_CD  = B.GATE_CD
	  AND BDHD.BUYER_CD = B.BUYER_CD
	  AND BDHD.BID_NUM  = B.BID_NUM
	  AND BDHD.BID_CNT  = B.BID_CNT)
