DELETE FROM STOCBDAP
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM = #{BID_NUM}
   AND BID_CNT = #{BID_CNT}

DELETE FROM STOCBDEU
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND EI_NUM = #{EI_NUM}

mapper.insert:

	SELECT (CASE WHEN (TO_CHAR(#{EU_SQ}), '-') = '-' THEN (MAX(EU_SQ), 0) + 1 ELSE TO_NUMBER(#{EU_SQ}) END) FROM STOCBDEU
	 WHERE GATE_CD = #{ses.gateCd}
	   AND BUYER_CD = #{BUYER_CD}
	   AND EI_NUM = #{EI_NUM}


INSERT INTO STOCBDEU (
	 GATE_CD
	,BUYER_CD
	,EI_NUM
	,EU_SQ
	,REG_DATE
	,REG_USER_ID
	,MOD_DATE
	,MOD_USER_ID
	,DEL_FLAG
	,EU_TYPE
	,EU_USER_ID
	,EU_USER_NM
	,EU_PHONE_NUM
	,EU_EMAIL
	,PROGRESS_CD
	,EU_REQ_DATE
) VALUES (
	 #{ses.gateCd}
	,#{BUYER_CD}
	,#{EI_NUM}


		,(SELECT (MAX(EU_SQ), 0) + 1 FROM STOCBDEU
